  "žŻ┘łž▒┘łž©ž¦":             0.75,
  "žóž│┘Ŗž¦ ┘łž¦┘ä┘ģžŁ┘ŖžĘ ž¦┘ä┘ćž¦ž»ž”": 0.70,
  "žŻ┘ģž▒┘Ŗ┘āž¦ ž¦┘äž┤┘ģž¦┘ä┘Ŗž®":    0.65,
  "žŻ┘üž▒┘Ŗ┘é┘Ŗž¦":            0.60,
  "žŻ┘ģž▒┘Ŗ┘āž¦ ž¦┘ä┘äž¦ž¬┘Ŗ┘å┘Ŗž®":   0.50,
