// ŌöĆŌöĆ Severity Thresholds ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
const SEVERITY_THRESHOLDS = {
  critical: 75,  // žŁž▒ž¼
  high: 50,      // ┘ģž▒ž¬┘üž╣
  medium: 25,    // ┘ģž¬┘łž│žĘ
};

/**
 * Classify a radar signal ŌåÆ { severity, alertBadge, isEmerging }
 */
export function classifySignal(signal) {
  const score = signal.radarScore || 0;
  const cat = signal.category || "";
  const urgency = signal.urgency || "low";
  const confidence = signal.confidence || 50;
  const sourceCount = signal.sourceCount || 1;

  // Severity
  let severity;
  if (score >= SEVERITY_THRESHOLDS.critical) severity = "žŁž▒ž¼";
  else if (score >= SEVERITY_THRESHOLDS.high) severity = "┘ģž▒ž¬┘üž╣";
  else if (score >= SEVERITY_THRESHOLDS.medium) severity = "┘ģž¬┘łž│žĘ";
  else severity = "┘ģ┘åž«┘üžČ";

  // Is emerging?
  const isEmerging = sourceCount <= 2 && confidence < 50 && score < 50 && score >= 15;

  // Alert badge
  let alertBadge = null;
  if (score >= 80 && (cat === "žĄž▒ž¦ž╣ / ž¬žĄž╣┘Ŗž»")) {
    alertBadge = "ž¬žĄž╣┘Ŗž» žŁž▒ž¼";
  } else if (urgency === "high" && score >= 65) {
    alertBadge = "ž╣ž¦ž¼┘ä";
  } else if (cat === "ž¦┘éž¬žĄž¦ž» / žŻž│┘łž¦┘é" || cat === "žĘž¦┘éž® / ┘å┘üžĘ / ž┤žŁ┘å") {
    if (score >= 50) alertBadge = "žŻž½ž▒ ž¦┘éž¬žĄž¦ž»┘Ŗ";
  } else if (cat === "ž▒┘Ŗž¦žČž®" || cat === "ž¦┘åž¬┘éž¦┘äž¦ž¬") {
    if (score >= 40) alertBadge = "žŻž½ž▒ ž▒┘Ŗž¦žČ┘Ŗ";
  } else if (isEmerging) {
    alertBadge = "žźž┤ž¦ž▒ž® ┘åž¦ž┤ž”ž®";
  } else if (score >= 40 && score < 65) {
    alertBadge = "ž¬žŁž¬ ž¦┘ä┘ģž▒ž¦┘éž©ž®";
  }

  return { severity, alertBadge, isEmerging };
}

